function buildSessionDockPanel(
  binding: ChannelBinding,
  expanded = true,
  options?: {
    bordered?: boolean;
    padding?: string;
    verticalSpacing?: string;
    title?: string;
  },
): Record<string, unknown> {
  const items = getSessionDockItems(binding);
  const runningCount = items.filter((item) => item.running).length;
  const unreadCount = items.reduce((total, item) => total + (item.current ? 0 : item.unreadCount), 0);
  const projectCount = new Set(items.map((item) => item.projectLabel)).size;
  const elements: Array<Record<string, unknown>> = [];
  const bordered = options?.bordered ?? true;
  const padding = options?.padding ?? '8px';
  const verticalSpacing = options?.verticalSpacing ?? '4px';
  const dockSummary = `${items.length} open${projectCount > 1 ? ` · ${projectCount} projects` : ''}${runningCount ? ` · ${runningCount} running` : ''}${unreadCount ? ` · ${unreadCount} unread` : ''}`;
  const title = options?.title
    ?? `**Open Sessions** · ${dockSummary}`;

  if (items.length === 0) {
    elements.push({
      tag: 'markdown',
      content: 'No opened sessions yet.',
      text_size: 'normal',
    });
  } else {
    items.forEach((item) => {
      const indicator = getDockIndicator(item);
      const statusParts = [
        item.current ? 'current' : null,
        item.running ? 'run' : null,
        item.unreadCount > 0 && !item.current ? `+${item.unreadCount}` : null,
      ].filter(Boolean);
      const statusSuffix = statusParts.length > 0 ? ` · ${statusParts.join(' · ')}` : '';
      const title = `${indicator} ${item.projectLabel}/${getShortSessionId(item.sessionId)} · ${item.messageCount} msg${statusSuffix}`;
      elements.push(createDockButtonRow(
        {
          label: title,
          callbackData: `nav:dock:select:${item.sessionId}`,
          type: item.current ? 'primary' : 'default',
          extras: {
            nav: 'dock_select',
            session_id: item.sessionId,
          },
        },
        items.length > 1 ? {
          callbackData: `nav:dock:close:${item.sessionId}`,
          extras: {
            nav: 'dock_close',
            session_id: item.sessionId,
          },
        } : undefined,
      ));
    });
  }

  return {
    tag: 'collapsible_panel',
    expanded,
    ...(bordered ? {
      border: {
        color: 'grey',
        corner_radius: '6px',
      },
    } : {}),
    header: {
      title: {
        tag: 'markdown',
        content: title,
      },
      icon_position: 'follow_text',
      icon_expanded_angle: -180,
    },
    padding,
    vertical_spacing: verticalSpacing,
    elements,
  };
}

function buildFeishuProjectListCard(
  groups: ProjectGroup[],
  binding: ChannelBinding,
  scope: ProjectListScope = 'global',
): string {
  const projectLabel = getProjectLabel(binding.workingDirectory);
  const elements: Array<Record<string, unknown>> = [
    buildSessionDockPanel(binding, false, {
      bordered: false,
      padding: '0px',
      verticalSpacing: '2px',
      title: `**Open Sessions** · ${getOpenSessionIds(binding).length} open`,
    }),
  ];

  if (groups.length === 0) {
    elements.push({ tag: 'hr' });
    elements.push({
      tag: 'markdown',
      content: 'No projects found yet.',
    });
  } else {
    groups.slice(0, 12).forEach((group, index) => {
      if (index === 0) {
        elements.push({ tag: 'hr' });
      }
      elements.push(createCardButtonRow(
        `${group.label}${group.current ? ' · Current' : ''} · ${formatSessionCount(group.sessions.length)}`,
        `nav:project:${scope}:${encodeCardToken(group.path)}`,
        group.current ? 'primary' : 'default',
        {
          nav: 'project',
          project_path: group.path,
          scope,
        },
      ));
      if (index < groups.length - 1) {
        elements.push({ tag: 'hr' });
      }
    });
  }

  return JSON.stringify({
    schema: '2.0',
    config: { wide_screen_mode: true, update_multi: true },
    header: {
      title: { tag: 'plain_text', content: scope === 'workspace' ? projectLabel : 'Projects' },
      template: 'default',
      text_tag_list: [
        {
          tag: 'text_tag',
          text: {
            tag: 'plain_text',
            content: scope === 'workspace' ? 'Workspace' : 'Global',
          },
          color: scope === 'workspace' ? 'blue' : 'wathet',
        },
        {
          tag: 'text_tag',
          text: {
            tag: 'plain_text',
            content: formatProjectCount(groups.length),
          },
          color: 'grey',
        },
      ],
    },
    body: { elements },
  });
}

function buildFeishuProjectSessionsCard(
  group: ProjectGroup,
  currentSessionId: string,
  binding?: ChannelBinding,
  scope: ProjectListScope = 'workspace',
): string {
  const sessionItems: FeishuSessionCardItem[] = group.sessions.slice(0, 12).map((session) => ({
    sessionId: session.id,
    title: getSessionTitle(session),
    subtitle: `${getShortSessionId(session.id)} · ${formatMessageCount(getSessionMessageCount(session.id))} · ${session.model || 'default'}`,
    current: session.id === currentSessionId,
    messageCount: getSessionMessageCount(session.id),
  }));

  const elements: Array<Record<string, unknown>> = [
    createSummaryActionRow('Back to project list', '◂ Projects', `nav:projects:${scope}`, 'default', {
      nav: 'projects',
      scope,
    }),
    ...(binding ? [buildSessionDockPanel(binding, false, {
      bordered: false,
      padding: '0px',
      verticalSpacing: '2px',
      title: `**Open Sessions** · ${getOpenSessionIds(binding).length} open`,
    })] : []),
    { tag: 'hr' },
  ];

  if (sessionItems.length === 0) {
    elements.push({
      tag: 'markdown',
      content: 'No sessions found for this project.',
    });
  } else {
    sessionItems.forEach((session, index) => {
      const lines = [`**${escapeCardText(session.title)}**`];
      if (!session.current || session.title !== getShortSessionId(session.sessionId)) {
        lines.push(`\`${escapeCardText(session.subtitle)}\``);
      }
      elements.push({
        tag: 'markdown',
        content: lines.join('\n'),
      });
      elements.push(createInlineCardButtonSet([
        {
          label: session.current ? 'Current' : 'Use',
          callbackData: `nav:bind:${session.sessionId}`,
          type: session.current ? 'primary' : 'default',
          extras: {
            nav: 'bind',
            session_id: session.sessionId,
          },
        },
        {
          label: 'Ctx',
          callbackData: `nav:peek:${session.sessionId}`,
          type: 'default',
          extras: {
            nav: 'peek',
            session_id: session.sessionId,
          },
        },
        {
          label: 'Arc',
          callbackData: `nav:archive:${session.sessionId}`,
          type: 'default',
          extras: {
            nav: 'archive',
            session_id: session.sessionId,
          },
        },
      ]));
      if (index < sessionItems.length - 1) {
        elements.push({ tag: 'hr' });
      }
    });
  }

  return JSON.stringify({
    schema: '2.0',
    config: { wide_screen_mode: true, update_multi: true },
    header: {
      title: { tag: 'plain_text', content: group.label },
      template: 'default',
      text_tag_list: [
        {
          tag: 'text_tag',
          text: {
            tag: 'plain_text',
            content: scope === 'workspace' ? 'Workspace' : 'Global',
          },
          color: scope === 'workspace' ? 'blue' : 'wathet',
        },
        {
          tag: 'text_tag',
          text: {
            tag: 'plain_text',
            content: formatSessionCount(group.sessions.length),
          },
          color: 'blue',
        },
      ],
    },
    body: { elements },
  });
}

